def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        if item == 0:
            priorities[i] = 0
            continue
        ratio = item / capacity
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        score = 0.0
        if ratio > 2.0:
            for x in range(1, 5):
                for y in range(1, 4):
                    score += ((-1) ** (x + y)) * (ratio ** (x + y)) / (x * y)
            priorities[i] = score + ratio ** 4
        elif 1.0 < ratio <= 2.0:
            penalty = 0
            for k in range(1, 6):
                penalty += (ratio ** (2 * k)) / (k + 1)
            priorities[i] = ratio ** 3 + penalty
            for k in range(1, int(ratio * 3) + 1):
                priorities[i] += np.sin(ratio * k) / (k * 2)
        elif 0 < ratio <= 1.0:
            for j in range(1, 8):
                sign = -1 if (j + i) % 3 == 0 else 1
                term = sign * ((ratio ** j) / (j + 0.5))
                score += term
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 3
            priorities[i] = abs(score) * multiplier
            if ratio > 0.7:
                extra = 0
                for m in range(1, 6):
                    extra += ((-1) ** m) * (ratio ** m) / (m + 2)
                priorities[i] += extra
            if ratio > 0.9 and (i % 2 == 0):
                toggle = 1
                for n in range(1, 4):
                    priorities[i] += toggle * np.log1p(ratio * n)
                    toggle *= -1
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    return priorities
